<?php $resumo=$resumo??[]; $total=(int)($resumo['total']??0); ?>
<div class="page-header page-header-modern"><div><span class="breadcrumb">Administração &gt; Catálogo</span><h1>Tipos de ajuda humanitária</h1><p>Materiais configurados para ações de ajuda humanitária.</p></div><a class="button button-primary" href="<?= e(url('/tipos-ajuda/novo')); ?>">Novo tipo</a></div>
<section class="aid-type-overview-grid" aria-label="Indicadores de tipos de ajuda"><article><span>Tipos cadastrados</span><strong><?= e($total); ?></strong><small>Total de materiais configurados.</small></article><article><span>Ativos</span><strong><?= e((int)($resumo['ativos']??0)); ?></strong><small>Disponíveis para novas entregas.</small></article><article><span>Inativos</span><strong><?= e((int)($resumo['inativos']??0)); ?></strong><small>Indisponíveis para novos registros.</small></article><article><span>Unidades de medida</span><strong><?= e((int)($resumo['unidades']??0)); ?></strong><small>Formas de distribuição cadastradas.</small></article></section>
<form method="get" class="compdec-filter-panel"><div class="field compdec-filter-search"><label for="busca">Busca inteligente</label><input id="busca" name="busca" value="<?= e($filtros['busca']); ?>" placeholder="Material ou unidade"></div><div class="field"><label for="status">Status</label><select id="status" name="status"><option value="">Todos</option><option value="ativo" <?= $filtros['status']==='ativo'?'selected':''; ?>>Ativo</option><option value="inativo" <?= $filtros['status']==='inativo'?'selected':''; ?>>Inativo</option></select></div><div class="field"><label for="unidade">Unidade</label><select id="unidade" name="unidade"><option value="">Todas</option><?php foreach($unidades as $u): ?><option value="<?= e($u['unidade_medida']); ?>" <?= $filtros['unidade']===$u['unidade_medida']?'selected':''; ?>><?= e($u['unidade_medida']); ?></option><?php endforeach; ?></select></div><div class="compdec-filter-actions"><button class="button button-primary">Filtrar</button><a class="button button-light" href="<?= e(url('/tipos-ajuda')); ?>">Limpar</a></div></form>
<div class="aid-type-list-toolbar"><span><?= e($total); ?> tipo(s) encontrado(s)</span></div>
<section class="aid-type-card-list"><?php foreach($tipos as $tipo): $ativo=(int)$tipo['ativo']===1; ?><article class="aid-type-card"><div class="aid-type-main"><header><span class="status-badge <?= $ativo?'badge-success':'badge-muted'; ?>"><?= $ativo?'Ativo':'Inativo'; ?></span><h2><?= e($tipo['nome']); ?></h2><p><?= $ativo?'Disponível para novas entregas.':'Indisponível para novas entregas.'; ?></p></header><dl><div><dt>Unidade</dt><dd><?= e($tipo['unidade_medida']); ?></dd></div><div><dt>Criado em</dt><dd><?= e(date('d/m/Y H:i',strtotime($tipo['criado_em']))); ?></dd></div><div><dt>Entregas</dt><dd><?= e((int)$tipo['entregas_registradas']); ?></dd></div></dl></div><aside class="aid-type-actions"><a class="button button-light" href="<?= e(url('/tipos-ajuda/'.$tipo['id'].'/editar')); ?>">Editar</a><form method="post" action="<?= e(url('/tipos-ajuda/'.$tipo['id'].'/status')); ?>" data-confirm="<?= $ativo?'Inativar este tipo de ajuda?':'Ativar este tipo de ajuda?'; ?>"><?= csrf_input(); ?><input type="hidden" name="ativo" value="<?= $ativo?'0':'1'; ?>"><button class="button button-secondary"><?= $ativo?'Inativar':'Ativar'; ?></button></form><form method="post" action="<?= e(url('/tipos-ajuda/'.$tipo['id'].'/excluir')); ?>" data-confirm="Excluir definitivamente este tipo de ajuda?"><?= csrf_input(); ?><button class="button button-danger">Excluir</button></form></aside></article><?php endforeach; ?><?php if($tipos===[]): ?><div class="compdec-empty-state"><div><strong>Nenhum tipo de ajuda encontrado</strong><p>Cadastre um novo tipo ou revise os filtros.</p></div></div><?php endif; ?></section>
